USTRUCT(BlueprintType)
struct FCameraState {
	GENERATED_BODY()
	UPROPERTY(EditAnywhere)
	int Priority = 0;

	//spring arm length
	UPROPERTY(EditAnywhere)
	float TargetArmLength = 1400.f;
	//spring arm socket offset
	UPROPERTY(EditAnywhere)
	FVector SocketOffset = FVector::ZeroVector;
	//spring arm target offset
	UPROPERTY(EditAnywhere)
	FVector TargetOffset = FVector::ZeroVector;

	//Decides whether fov gets overriden
	UPROPERTY(EditAnywhere)
	bool bOverrideFOV = false;
	//The overriden fov
	UPROPERTY(EditAnywhere, meta=(EditCondition="bOverrideFOV"))
	float FieldOfView = 90.f;

	//Decides whether control rotation gets overriden
	UPROPERTY(EditAnywhere)
	bool bOverrideControlRotation = false;
	//The overriden control rotation. In local space, relative to the pawn's rotation
	UPROPERTY(EditAnywhere, meta=(EditCondition="bOverrideControlRotation"))
	FRotator ControlRotation = FRotator::ZeroRotator;

	UPROPERTY(EditAnywhere)
	float InterpSpeed = 5.f;
};
